import json, re, sys

# Use python to fetch from multiple sources
import urllib.request
import urllib.error

def fetch_url(url, headers=None):
    if headers is None:
        headers = {'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'}
    try:
        req = urllib.request.Request(url, headers=headers)
        with urllib.request.urlopen(req, timeout=15) as resp:
            return resp.read().decode('utf-8', errors='replace')
    except Exception as e:
        return f"ERROR: {e}"

# Let me try DuckDuckGo HTML interface first
html = fetch_url("https://html.duckduckgo.com/html/?q=AI+industry+competitive+landscape+2025+OpenAI+Anthropic+Google+Meta+DeepSeek")
# Extract result snippets
snippets = re.findall(r'class="result__snippet"[^>]*>(.*?)</a>', html, re.DOTALL)
if snippets:
    for i, s in enumerate(snippets[:5]):
        clean = re.sub(r'<[^>]+>', '', s).strip()[:200]
        print(f"Snippet {i+1}: {clean}")
else:
    print("No snippets found. HTML length:", len(html))
    print("First 500 chars:", html[:500])
